import{_ as d,o as a,c as r,a7 as e}from"./chunks/framework.C5fSpjcB.js";const b=JSON.parse('{"title":"召唤系统（Gacha）","description":"","frontmatter":{},"headers":[],"relativePath":"modes/gacha.md","filePath":"zh/modes/gacha.md","lastUpdated":1775394001000}'),l={name:"modes/gacha.md"};function h(o,t,i,n,s,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="召唤系统-gacha" tabindex="-1">召唤系统（Gacha） <a class="header-anchor" href="#召唤系统-gacha" aria-label="Permalink to &quot;召唤系统（Gacha）&quot;">​</a></h1><h2 id="召唤类型" tabindex="-1">召唤类型 <a class="header-anchor" href="#召唤类型" aria-label="Permalink to &quot;召唤类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th><th>使用货币</th><th>保底机制</th></tr></thead><tbody><tr><td>灵识黑潮 (The Unforgotten)</td><td>常驻SSR角色池，无UP机制。每30抽保底SSR。5次唤醒保底SSR+命轮</td><td>无垢之芯</td><td>30抽保底</td></tr><tr><td>限定活动唤醒 (Obsidian Wings)</td><td>新限定角色首发池。限定SSR不进入常驻</td><td>流明之芯</td><td>30抽保底</td></tr><tr><td>万华追忆 (Kaleido Recollections)</td><td>纯限定角色池，不含常驻SSR。30抽内保底限定SSR角色或命轮</td><td>流明之芯</td><td>30抽保底</td></tr><tr><td>复刻池 (Rerun Banner)</td><td>往期限定角色复刻</td><td>流明之芯</td><td>30抽保底</td></tr><tr><td>必得唤醒 (Guaranteed Awakening)</td><td>付费保底池，5次保底2个随机限定SSR角色+3个随机限定SSR命轮。分旧世篇/星辰篇、男/女子池</td><td>源液x980/次</td><td>5次保底</td></tr><tr><td>自选唤醒 (Self-Select Awakening)</td><td>活动限定池，可自选1个SSR角色+其专属命轮作为UP目标</td><td>不定</td><td>有</td></tr></tbody></table><h2 id="概率说明" tabindex="-1">概率说明 <a class="header-anchor" href="#概率说明" aria-label="Permalink to &quot;概率说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>稀有度</th><th>基础概率</th><th>备注</th></tr></thead><tbody><tr><td><span class="rarity-ssr">SSR</span></td><td>3%</td><td>v2.0大改后出率，原v1.x为1.02%</td></tr><tr><td><span class="rarity-sr">SR</span></td><td>~15%</td><td>每5抽保底1个SR或更高</td></tr><tr><td><span class="rarity-r">R</span></td><td>~82%</td><td>剩余概率</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">概率变更历史</p><p>v2.0重大改革：SSR基础出率从1.02%提升至3%，保底从80抽降低至30抽。游戏对玩家非常友好。</p></div><h2 id="保底机制" tabindex="-1">保底机制 <a class="header-anchor" href="#保底机制" aria-label="Permalink to &quot;保底机制&quot;">​</a></h2><table tabindex="0"><thead><tr><th>保底类型</th><th>说明</th></tr></thead><tbody><tr><td>小保底</td><td><strong>30抽</strong> 必出SSR（v2.0后，原v1.x为80抽）</td></tr><tr><td>UP概率</td><td>抽到SSR时，33.33%概率为UP角色/命轮</td></tr><tr><td>递增保底</td><td>第1次SSR若歪(非UP)，第2次SSR有66.66%概率为UP；若仍歪，第3次100%为UP</td></tr><tr><td>大保底</td><td><strong>120抽</strong> 内必获UP角色（4个30抽周期内）</td></tr><tr><td>防重复</td><td>连续两次获得相同UP物品后，下次UP必为另一个UP物品</td></tr><tr><td>跨池独立</td><td>限定池与常驻池保底独立计算，各自维护计数器</td></tr></tbody></table><h2 id="召唤货币" tabindex="-1">召唤货币 <a class="header-anchor" href="#召唤货币" aria-label="Permalink to &quot;召唤货币&quot;">​</a></h2><table tabindex="0"><thead><tr><th>货币</th><th>类型</th><th>用途</th><th>获取途径</th></tr></thead><tbody><tr><td>源液 (Silver Prime)</td><td>付费货币</td><td>购买抽卡资格、通行证、礼盒</td><td>充值（标准档位：6/30/68/128/198/328/648元）</td></tr><tr><td>银芯 (Silver Core)</td><td>基础高级货币</td><td>兑换流明/无垢之芯（约200银芯=1抽）</td><td>每日任务、主线评分、活动奖励、通行证、兑换码</td></tr><tr><td>流明之芯 (Lumen Core)</td><td>限定抽卡货币</td><td>限定池抽卡，1个=1抽</td><td>银芯兑换、活动奖励、通行证（优先兑换）</td></tr><tr><td>无垢之芯 (Pure Core)</td><td>常驻抽卡货币</td><td>常驻池/命轮池抽卡，1个=1抽</td><td>银芯兑换、活动奖励、角色首次升格、纪行(40个)、章节首通</td></tr><tr><td>沉淀币 (Sediment Currency)</td><td>抽卡副产物</td><td>沉淀商店兑换</td><td>抽卡时副产品</td></tr></tbody></table><h2 id="新手福利" tabindex="-1">新手福利 <a class="header-anchor" href="#新手福利" aria-label="Permalink to &quot;新手福利&quot;">​</a></h2><ul><li>开服赠送1500银芯(约7抽) + 普池15抽</li><li>累计登录7天额外送10抽活动池</li><li>达到35级时最高可获40抽普池 + 2000银芯(10抽)</li><li>累计登录3天、7天各送1次常驻自选SSR</li><li>累计抽卡50次送1次常驻自选SSR</li><li>7天后至少拥有3只以上SSR角色</li><li>每周轮换唤醒活动首5抽免费(活动期间最多20抽免费)</li></ul><h2 id="抽卡建议" tabindex="-1">抽卡建议 <a class="header-anchor" href="#抽卡建议" aria-label="Permalink to &quot;抽卡建议&quot;">​</a></h2><ol><li><strong>普池先下角色池</strong> - 只用送的无垢之芯</li><li><strong>抽齐核心角色收手</strong> - 不要过度追求满命</li><li><strong>剩余无垢下武器池</strong> - 拿专武提升战力</li><li><strong>银芯和流明只冲限定池</strong> - 限定角色过期后难以获取</li><li><strong>限定池保底不跨池共享</strong> - 限定与常驻独立计算</li><li><strong>F2P优先确保24</strong> - 其次墨菲，两者为最强投资</li></ol><h2 id="充值指南" tabindex="-1">充值指南 <a class="header-anchor" href="#充值指南" aria-label="Permalink to &quot;充值指南&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>价格</th><th>收益</th><th>性价比</th></tr></thead><tbody><tr><td>月卡</td><td>约30元</td><td>3300银芯(分30天) + 每日3个现实起点</td><td>约16.5抽等价，最高性价比</td></tr><tr><td>纪行高级轨道</td><td>源液x980</td><td>流明之芯x40 + 银芯x2000 + 专属外观</td><td>推荐购买</td></tr><tr><td>纪行免费轨道</td><td>免费</td><td>无垢之芯x40 + 银芯x2000</td><td>不要漏领</td></tr><tr><td>必得唤醒礼包</td><td>源液x980/次</td><td>5次保底2个随机限定SSR角色+3个随机限定SSR命轮</td><td>看脸</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">特殊活动纪行</p><p>特殊活动纪行(降临/异世/疗养/亡城)期间免费轨道奖励翻倍：额外无垢之芯x80 + 银芯x4000。</p></div>',17)])])}const u=d(l,[["render",h]]);export{b as __pageData,u as default};
